query GetCampaignAttribution($campaignOrderId: ID!) {
  campaignOrder(where: { id: $campaignOrderId }) {
    id
    name
    status
    startDate
    endDate
    budget
    aggregateData {
      id
      completeAttributionSummary
      byDate
      topCreatives
      topPublishers
      deviceClicks
    }
  }
}

query GetMultipleCampaignAttribution($first: Int, $where: CampaignOrderWhereInput, $orderBy: CampaignOrderOrderByInput) {
  campaignOrdersConnection(first: $first, where: $where, orderBy: $orderBy) {
    edges {
      node {
        id
        name
        status
        startDate
        endDate
        aggregateData {
          id
          completeAttributionSummary
          byDate
        }
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}

query GetCampaignAttributionByDateRange($first: Int, $where: CampaignOrderWhereInput, $orderBy: CampaignOrderOrderByInput) {
  campaignOrdersConnection(first: $first, where: $where, orderBy: $orderBy) {
    edges {
      node {
        id
        name
        status
        startDate
        endDate
        aggregateData {
          id
          completeAttributionSummary
        }
      }
    }
    aggregate {
      count
    }
  }
}
